const raw = msg.payload;

if (!raw.zone || raw.aqi === undefined || raw.temperature === undefined || raw.humidity === undefined) {
    node.warn('[ENV] Payload tidak lengkap, dibuang: ' + JSON.stringify(raw));
    return null;
}

msg.payload = {
    sensor_id      : raw.sensor_id    || 'NODE-RED-BRIDGE',
    zone           : String(raw.zone).toUpperCase(),
    aqi            : parseFloat(raw.aqi),
    aqi_status     : raw.aqi_status   || null,
    pm25           : raw.pm25  !== undefined ? parseFloat(raw.pm25)  : null,
    pm10           : raw.pm10  !== undefined ? parseFloat(raw.pm10)  : null,
    no2            : raw.no2   !== undefined ? parseFloat(raw.no2)   : null,
    co             : raw.co    !== undefined ? parseFloat(raw.co)    : null,
    o3             : raw.o3    !== undefined ? parseFloat(raw.o3)    : null,
    temperature    : parseFloat(raw.temperature),
    humidity       : parseFloat(raw.humidity),
    rain_level     : raw.rain_level     !== undefined ? parseFloat(raw.rain_level)     : 0,
    rain_intensity : raw.rain_intensity !== undefined ? parseFloat(raw.rain_intensity) : 0,
    rain_status    : raw.rain_status    || null,
    flood_level    : parseFloat(raw.flood_level || 0),
    flood_status   : raw.flood_status   || null,
    recorded_at    : new Date().toISOString().replace('T', ' ').slice(0, 19)
};

const token = flow.get('IOT_JWT_TOKEN');if (!token) {node.warn('[ENV] Token belum tersedia, payload di-skip & masuk antrian.');flow.set('pendingEnvQueue', (flow.get('pendingEnvQueue') || []).concat([msg.payload]));return null;}msg.headers = {'Content-Type' : 'application/json','Authorization': 'Bearer ' + token};
msg.url = (env.get('API_GATEWAY_URL') || 'http://api-gateway:3000') + '/api/environment/sensor';

node.log('[ENV] zone=' + msg.payload.zone + ' aqi=' + msg.payload.aqi + ' rain=' + msg.payload.rain_intensity);
return msg;

const raw = msg.payload;

if (!raw.zone || raw.vehicle_count === undefined) {
    node.warn('[VEHICLE] Payload tidak lengkap: ' + JSON.stringify(raw));
    return null;
}

// Untuk korelasi ML, coba ambil data rain dari context flow
// (diset oleh flow env saat subscribe city/+/air)
const lastEnvByZone = flow.get('lastEnv_' + String(raw.zone).toUpperCase()) || {};

msg.payload = {
    sensor_id      : raw.sensor_id    || 'NODE-RED-IR',
    zone           : String(raw.zone).toUpperCase(),
    vehicle_count  : parseInt(raw.vehicle_count),
    interval_sec   : parseInt(raw.interval_sec || 60),
    traffic_status : raw.traffic_status || null,
    // Ambil rain context dari env data terbaru di zona ini
    rain_intensity : lastEnvByZone.rain_intensity || parseFloat(raw.rain_intensity || 0),
    rain_status    : lastEnvByZone.rain_status    || raw.rain_status || null,
    flood_level    : lastEnvByZone.flood_level    || parseFloat(raw.flood_level || 0),
    recorded_at    : new Date().toISOString().replace('T', ' ').slice(0, 19)
};

const token = flow.get('IOT_JWT_TOKEN');if (!token) {node.warn('[VEHICLE] Token belum tersedia, payload di-skip & masuk antrian.');flow.set('pendingVehicleQueue', (flow.get('pendingVehicleQueue') || []).concat([msg.payload]));return null;}msg.headers = {'Content-Type' : 'application/json','Authorization': 'Bearer ' + token};
msg.url = (env.get('API_GATEWAY_URL') || 'http://api-gateway:3000') + '/api/environment/vehicle';

node.log('[VEHICLE] zone=' + msg.payload.zone + ' count=' + msg.payload.vehicle_count + ' rain=' + msg.payload.rain_intensity);
return msg;

const queue = flow.get('pendingEnvQueue') || [];
if (queue.length === 0) return null;
const item = queue.shift();
flow.set('pendingEnvQueue', queue);
msg.payload = item;
msg.url = (env.get('API_GATEWAY_URL') || 'http://api-gateway:3000') + '/api/environment/sensor';
msg.headers = { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (env.get('IOT_JWT_TOKEN') || 'IOT_TOKEN_PLACEHOLDER') };
return msg;

const queue = flow.get('pendingVehicleQueue') || [];
if (queue.length === 0) return null;
const item = queue.shift();
flow.set('pendingVehicleQueue', queue);
msg.payload = item;
msg.url = (env.get('API_GATEWAY_URL') || 'http://api-gateway:3000') + '/api/environment/vehicle';
msg.headers = { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (env.get('IOT_JWT_TOKEN') || 'IOT_TOKEN_PLACEHOLDER') };
return msg;

const exp = flow.get('iot_token_exp') || 0;
const now = Date.now();

// kasih buffer 60 detik sebelum expired biar gak mepet
if (now < exp - 60000) {
    node.status({ fill: 'green', shape: 'dot', text: 'token valid' });
    return null; // skip, token masih valid
}

node.status({ fill: 'yellow', shape: 'ring', text: 'refreshing...' });
return msg;

const authUrl = env.get('AUTH_SERVICE_URL') || 'http://auth-service:3002';

msg.url = authUrl + '/oauth/token';
msg.method = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    grant_type: 'client_credentials',
    client_id: env.get('IOT_CLIENT_ID') || 'iot-environment-device',
    client_secret: env.get('IOT_CLIENT_SECRET') || ''
};

node.log('[AUTH] Requesting new token from ' + msg.url);
return msg;

if (msg.statusCode === 200 && msg.payload && msg.payload.access_token) {
    flow.set('IOT_JWT_TOKEN', msg.payload.access_token);
    const expiresInMs = (msg.payload.expires_in || 3600) * 1000;
    flow.set('iot_token_exp', Date.now() + expiresInMs);

    node.status({ fill: 'green', shape: 'dot', text: 'token refreshed' });
    node.log('[AUTH OK] Token refreshed, expires in ' + msg.payload.expires_in + 's');
} else {
    node.status({ fill: 'red', shape: 'ring', text: 'auth failed' });
    node.error('[AUTH FAILED] status=' + msg.statusCode + ' body=' + JSON.stringify(msg.payload));
}
return null;
